/** The results layer (unified remediation plan §3.1, issue #49): per case, in plain language with zero
 *  unexplained jargon: what the shown field physically is (axes/colors), the declared assumptions, the answer
 *  as a sentence a domain person can read, and the verdict: how good or bad the result is, derived from the
 *  case's own baked numbers (cited inline; never invented). The raw estimate items render under the answer. */

export interface CaseResults {
  /** what the visualization physically shows: axes, colors, what a feature in it means */
  calculates_en: string;
  calculates_es: string;
  /** the declared assumptions the result rests on */
  assumptions_en: string[];
  assumptions_es: string[];
  /** the answer as a plain sentence (contextualizes the estimate items shown with it) */
  answer_en: string;
  answer_es: string;
  /** the judgment: how good/bad, from the baked numbers, and what it can / cannot be trusted for */
  verdict_en: string;
  verdict_es: string;
}

